5	// ResolveEvidenceCaps returns the effective evidence caps for the given
6	// harness, applying defaults < project-wide < per-harness precedence
7	// (FEAT-022 §1a).
8	func (c *NewConfig) ResolveEvidenceCaps(harness string) evidence.Caps {
9		if c == nil || c.EvidenceCaps == nil {
10			return evidence.DefaultCaps()
11		}
12		project := evidence.CapsOverride{
13			MaxPromptBytes:       c.EvidenceCaps.MaxPromptBytes,
14			MaxInlinedFileBytes:  c.EvidenceCaps.MaxInlinedFileBytes,
15			MaxDiffBytes:         c.EvidenceCaps.MaxDiffBytes,
16			MaxGoverningDocBytes: c.EvidenceCaps.MaxGoverningDocBytes,
17		}
18		perHarness := make(map[string]evidence.CapsOverride, len(c.EvidenceCaps.PerHarness))
19		for name, h := range c.EvidenceCaps.PerHarness {
20			if h == nil {
21				continue
22			}
23			perHarness[name] = evidence.CapsOverride{
24				MaxPromptBytes:       h.MaxPromptBytes,
25				MaxInlinedFileBytes:  h.MaxInlinedFileBytes,
26				MaxDiffBytes:         h.MaxDiffBytes,
27				MaxGoverningDocBytes: h.MaxGoverningDocBytes,
28			}
29		}
30		return evidence.ResolveCaps(project, perHarness, harness)
31	}
